<script>
(function () {
'use strict';

var THEME_KEY = 'yoru_theme', LAYOUT_KEY = 'yoru_layout', RADICAL_KEY = 'yoru_radical';
var isXrayMode = false;

window.setTheme = function (id) {
  document.documentElement.setAttribute('data-theme', id === 'dark' ? '' : id);
  document.querySelectorAll('.theme-chip').forEach(function (c) { c.classList.toggle('active', c.getAttribute('data-theme-id') === id); });
  try { localStorage.setItem(THEME_KEY, id); } catch(e) {}
  try { if (window.Android && typeof Android.saveTheme === 'function') Android.saveTheme(id); } catch(e) {}
};
function loadTheme() {
  var saved = null;
  try { if (window.Android && typeof Android.getSavedTheme === 'function') saved = Android.getSavedTheme(); } catch(e) {}
  if (!saved) { try { saved = localStorage.getItem(THEME_KEY); } catch(e) {} }
  if (saved && saved !== 'dark') setTheme(saved);
}

window.setLayout = function (id) {
  document.documentElement.setAttribute('data-layout', id === 'default' ? '' : id);
  document.querySelectorAll('#layout-grid .layout-chip').forEach(function (c) { c.classList.toggle('active', c.getAttribute('data-layout-id') === id); });
  try { localStorage.setItem(LAYOUT_KEY, id); } catch(e) {}
  try { if (window.Android && typeof Android.saveLayout === 'function') Android.saveLayout(id); } catch(e) {}
  toast('Estilo visual aplicado!', 'ok');
};
function loadLayout() {
  var saved = null;
  try { if (window.Android && typeof Android.getSavedLayout === 'function') saved = Android.getSavedLayout(); } catch(e) {}
  if (!saved) { try { saved = localStorage.getItem(LAYOUT_KEY); } catch(e) {} }
  if (saved && saved !== 'default') setLayout(saved);
}

// ==================== NOVOS LAYOUTS RADICAIS ====================
var currentRadical = 'original';

function removeAllRadicals() {
    var mc = document.getElementById('minicards-overlay');
    if (mc) mc.style.display = 'none';
    var fo = document.getElementById('focus-overlay');
    if (fo) fo.style.display = 'none';
    var so = document.getElementById('slide-overlay');
    if (so) so.style.display = 'none';
    var cn = document.getElementById('compactnav-bar');
    if (cn) cn.style.display = 'none';
    var tc = document.getElementById('terminal-container');
    if (tc) tc.style.display = 'none';
    var shell = document.querySelector('.app-shell');
    var nav = document.querySelector('.bottom-nav');
    if (shell) shell.style.display = '';
    if (nav) nav.style.display = '';
    document.documentElement.removeAttribute('data-radical');
}

function applyRadical(id) {
    removeAllRadicals();
    if (id === 'original' || !id) {
        currentRadical = 'original';
        document.querySelectorAll('.page').forEach(function(p){ p.classList.remove('active'); });
        var home = document.getElementById('page-home');
        if (home) home.classList.add('active');
        return;
    }

    document.documentElement.setAttribute('data-radical', id);

    if (id === 'minicards') {
        applyMiniCards();
    } else if (id === 'focus') {
        applyFocus();
    } else if (id === 'slide') {
        applySlide();
    } else if (id === 'terminal') {
        applyTerminal();
    } else if (id === 'compactnav') {
        applyCompactNav();
    }
    currentRadical = id;
}

function applyMiniCards() {
    var overlay = document.getElementById('minicards-overlay');
    var grid = document.getElementById('minicards-grid');
    if (!overlay || !grid) return;
    overlay.style.display = 'block';
    document.querySelector('.app-shell').style.display = 'none';
    document.querySelector('.bottom-nav').style.display = 'none';

    var statusLabel = document.getElementById('status-label');
    var serverTitle = document.getElementById('server-title');

    grid.innerHTML = 
        '<div class="dash-card" onclick="var b=document.getElementById(\'btn-connect\');if(b)b.click();" style="grid-column:span 2;"><div class="dash-card-title">🔐 VPN</div><div class="dash-card-value">' + (statusLabel ? statusLabel.textContent : 'Desprotegido') + '</div></div>' +
        '<div class="dash-card" onclick="setRadical(\'original\');showPage(\'theme\');"><div class="dash-card-title">🎨 Tema</div><div class="dash-card-value" style="font-size:14px;">Personalizar</div></div>' +
        '<div class="dash-card" onclick="setRadical(\'original\');showPage(\'ajustes\');"><div class="dash-card-title">⚙️ Ajustes</div><div class="dash-card-value" style="font-size:14px;">Configurar</div></div>' +
        '<div class="dash-card" onclick="if(!app.connected){buildServerList(\'normal\');openModal(\'modal-servers\');}else{toast(\'Desconecte primeiro\',\'err\');}"><div class="dash-card-title">🌍 Servidor</div><div class="dash-card-value" style="font-size:14px;">' + (serverTitle ? serverTitle.textContent : 'Auto') + '</div></div>' +
        '<div class="dash-card" onclick="openGroupChat()"><div class="dash-card-title">💬 Grupo</div><div class="dash-card-value" style="font-size:14px;">Chat</div></div>';
}

function applyFocus() {
    var overlay = document.getElementById('focus-overlay');
    if (!overlay) return;
    overlay.style.display = 'flex';
    document.querySelector('.app-shell').style.display = 'none';
    document.querySelector('.bottom-nav').style.display = 'none';

    var btn = document.getElementById('focus-connect-btn');
    var statusEl = document.getElementById('focus-status');
    if (btn && statusEl) {
        btn.onclick = function() {
            var b = document.getElementById('btn-connect');
            if (b) b.click();
        };
        statusEl.textContent = document.getElementById('status-label') ? document.getElementById('status-label').textContent : '';
        setInterval(function() {
            if (statusEl) statusEl.textContent = document.getElementById('status-label') ? document.getElementById('status-label').textContent : '';
        }, 2000);
    }
