function applySlide() {
    var overlay = document.getElementById('slide-overlay');
    if (!overlay) return;
    overlay.style.display = 'block';
    document.querySelector('.app-shell').style.display = 'none';
    document.querySelector('.bottom-nav').style.display = 'none';

    var panelHome = document.getElementById('slide-panel-home');
    if (panelHome && panelHome.children.length === 0) {
        var hero = document.querySelector('.hero-area');
        if (hero) panelHome.appendChild(hero.cloneNode(true));
        var creds = document.getElementById('creds-card');
        if (creds) {
            var credsClone = creds.cloneNode(true);
            credsClone.querySelector('.btn-connect-main').onclick = function() { document.getElementById('btn-connect').click(); };
            panelHome.appendChild(credsClone);
        }
        var srv = document.getElementById('select-server');
        if (srv) panelHome.appendChild(srv.cloneNode(true));
        var prem = document.getElementById('select-premium');
        if (prem) panelHome.appendChild(prem.cloneNode(true));
    }
    var panelTheme = document.getElementById('slide-panel-theme');
    if (panelTheme && panelTheme.children.length === 0) {
        var themeContent = document.querySelector('#page-theme .theme-section');
        if (themeContent) panelTheme.appendChild(themeContent.cloneNode(true));
    }
    var panelAjustes = document.getElementById('slide-panel-ajustes');
