        if (timeCard) panelAjustes.appendChild(timeCard.cloneNode(true));
        var checkCard = document.getElementById('checkuser-card');
        if (checkCard) panelAjustes.appendChild(checkCard.cloneNode(true));
    }

    goSlide(0);
    document.querySelectorAll('.slide-dot').forEach(function(d) {
        d.onclick = function() { goSlide(parseInt(d.getAttribute('data-slide'))); };
    });
    var track = document.getElementById('slide-track');
    var startX = 0;
    if (track) {
        track.addEventListener('touchstart', function(e) { startX = e.touches[0].clientX; }, {passive:true});
        track.addEventListener('touchend', function(e) {
            var diff = startX - e.changedTouches[0].clientX;
            if (Math.abs(diff) > 50) {
                if (diff > 0 && slideIndex < 2) goSlide(slideIndex + 1);
                else if (diff < 0 && slideIndex > 0) goSlide(slideIndex - 1);
            }
        });
    }
}
function goSlide(idx) {
    slideIndex = idx;
    var t = document.getElementById('slide-track');
    if (t) t.style.transform = 'translateX(-' + (idx * 100) + '%)';
