function terminalExec(cmd) {
    var out = document.getElementById('terminal-output');
    if (!out) return;
    cmd = cmd.trim().toLowerCase();
    var response = '';
    if (cmd === 'help') {
        response = 'Comandos:\n  connect / disconnect\n  status\n  servers\n  logs\n  clear\n  exit';
    } else if (cmd === 'connect') {
        A.connect(); applyState('INICIANDO'); response = 'Conectando...';
    } else if (cmd === 'disconnect') {
        if (app.connected) { A.connect(); applyState('PARANDO'); response = 'Desconectando...'; }
        else response = 'Não conectado.';
    } else if (cmd === 'status') {
        response = 'Status: ' + app.rawState;
    } else if (cmd === 'servers') {
        var servers = A.getServers();
        response = servers.length ? servers.map(function(s, i) { return '  [' + i + '] ' + s.Name; }).join('\n') : 'Nenhum servidor.';
    } else if (cmd === 'logs') {
        var logs = A.getLogs();
        response = logs.length ? logs.slice(-5).map(function(l) { return '  [' + l.level + '] ' + l.message; }).join('\n') : 'Sem logs.';
    } else if (cmd === 'clear') {
        out.innerHTML = ''; return;
    } else if (cmd === 'exit') {
        setRadical('original'); return;
    } else if (cmd) {
        response = 'Comando desconhecido: ' + cmd;
    }
    if (response) out.innerHTML += '\n<span style="color:#0f0;">root@yoru:~$</span> ' + cmd + '\n' + response + '\n';
    out.scrollTop = out.scrollHeight;
}

