  setChk('cfg-wakelock', s.cpuWakeLock || false); setChk('cfg-debug', s.modeDebug || false);
  setChk('cfg-auto-clear', s.autoClearLogs !== undefined ? s.autoClearLogs : true); setChk('cfg-vibrate', s.vibrate !== undefined ? s.vibrate : true);
  updateDepRows();
}
function updateDepRows() {
  var dnsOn = ($('cfg-dns-forward') || {}).checked; document.querySelectorAll('.dep-dns').forEach(function(r) { r.style.opacity = dnsOn ? '1' : '0.35'; var inp = r.querySelector('input'); if (inp) inp.disabled = !dnsOn; });
  var udpOn = ($('cfg-udp-forward') || {}).checked; document.querySelectorAll('.dep-udp').forEach(function(r) { r.style.opacity = udpOn ? '1' : '0.35'; var inp = r.querySelector('input'); if (inp) inp.disabled = !udpOn; });
  var xrayOn = ($('cfg-xray-enabled') || {}).checked; document.querySelectorAll('.dep-xray').forEach(function(r) { r.style.opacity = xrayOn ? '1' : '0.35'; var sel = r.querySelector('select'); if (sel) sel.disabled = !xrayOn; });
}

function autoSaveSettings() {
  if (app.connected) return;
  function chk(id) { var el = $(id); return el ? el.checked : false; }
  function val(id) { var el = $(id); return el ? el.value.trim() : ''; }
  var obj = {
    dnsForward: chk('cfg-dns-forward'),
    dnsResolver: val('cfg-dns1')||'1.1.1.1',
    dnsResolver2: val('cfg-dns2')||'1.0.0.1',
    ipVersion: val('cfg-ip-version')||'auto',
    tlsVersion: val('cfg-tls-version')||'auto',
    udpForward: chk('cfg-udp-forward'),
    udpResolver: val('cfg-udp-resolver')||'127.0.0.1:7300',
    pinger: parseInt(val('cfg-pinger'))||3,
    adaptiveConnector: chk('cfg-adaptive'),
    sshCompression: chk('cfg-ssh-compression'),
    disableDelay: chk('cfg-no-delay'),
    xrayEnabled: chk('cfg-xray-enabled'),
    xrayProtocol: val('cfg-xray-protocol')||'vmess',
    cpuWakeLock: chk('cfg-wakelock'),
    modeDebug: chk('cfg-debug'),
    autoClearLogs: chk('cfg-auto-clear'),
    vibrate: chk('cfg-vibrate')
  };
  A.saveSettings(obj);
}

function updateCelestial() {
  var hour = new Date().getHours(), isDay = hour >= 6 && hour < 18;
  var celestial = document.querySelector('.celestial-body');
  if (celestial) { celestial.className = 'celestial-body ' + (isDay ? 'celestial-sun' : 'celestial-moon'); celestial.innerText = isDay ? '☀️' : '🌙'; }
}

/* ==================== INTEGRAÇÃO FIREBASE (CHAT / NOTIFICAÇÕES) ==================== */
var unreadCount = 0;
var lastSeenTimestamp = parseInt(localStorage.getItem('yoru_last_msg_ts') || '0');
var initialLoadDone = false;
var msgListenerUnsubscribe = null;
var _firestoreMaxTs = 0;

var unreadBadge = document.getElementById('unread-badge');
var newMsgBar = document.getElementById('new-msg-bar');
var newMsgText = document.getElementById('new-msg-text');

function updateBadge(count) {
    if (!unreadBadge) return;
    if (count > 0) {
        unreadBadge.textContent = count > 99 ? '99+' : count;
        unreadBadge.classList.add('show');
    } else {
        unreadBadge.classList.remove('show');
    }
}

function showNewMsgBar(sender) {
    if (!newMsgBar || !newMsgText) return;
    newMsgText.textContent = sender ? 'Nova mensagem de ' + sender : 'Nova mensagem no grupo';
    newMsgBar.classList.add('show');
    clearTimeout(window._newMsgTimeout);
    window._newMsgTimeout = setTimeout(function() {
        newMsgBar.classList.remove('show');
    }, 5000);
}

window.hideNewMsgBar = function() {
    if (newMsgBar) newMsgBar.classList.remove('show');
    clearTimeout(window._newMsgTimeout);
};

window.openGroupChat = function() {
    unreadCount = 0;
    updateBadge(0);
    var maxTs = _firestoreMaxTs || 0;
    if (maxTs > 0) {
        lastSeenTimestamp = maxTs;
        localStorage.setItem('yoru_last_msg_ts', lastSeenTimestamp);
    } else {
        lastSeenTimestamp = Date.now();
        localStorage.setItem('yoru_last_msg_ts', lastSeenTimestamp);
    }
    hideNewMsgBar();
    if (window.Android && typeof Android.openChat === 'function') {
        Android.openChat();
    } else {
        toast('Chat aberto (modo web)', '');
    }
};

function startMessageListener() {
    if (msgListenerUnsubscribe) return;
    if (typeof firebase === 'undefined' || !firebase.firestore) {
        console.warn('Firebase não disponível');
        return;
    }
    try {
        firebase.initializeApp({
            apiKey: "AIzaSyC_iO6eI-h948a_rU8BOLb0H_pKio1PD9M",
            authDomain: "um-network.firebaseapp.com",
            projectId: "um-network",
            storageBucket: "um-network.firebasestorage.app",
            messagingSenderId: "520410782376",
            appId: "1:520410782376:android:153633be6fda8273f2809d"
        });
        const db = firebase.firestore();
        msgListenerUnsubscribe = db.collection("mensagens")
            .orderBy("timestamp", "asc")
            .onSnapshot(function(snapshot) {
                var maxTs = 0;
                var newMessagesCount = 0;
                snapshot.docChanges().forEach(function(change) {
                    if (change.type !== 'added') return;
                    var data = change.doc.data();
                    if (!data || !data.timestamp) return;
                    var ts = data.timestamp.toMillis ? data.timestamp.toMillis() : data.timestamp;
                    if (ts > lastSeenTimestamp) newMessagesCount++;
                    if (ts > maxTs) maxTs = ts;
                });
                _firestoreMaxTs = maxTs || lastSeenTimestamp;
                if (!initialLoadDone) {
                    if (maxTs > 0) {
                        lastSeenTimestamp = maxTs;
                        localStorage.setItem('yoru_last_msg_ts', lastSeenTimestamp);
                    }
                    initialLoadDone = true;
                    return;
                }
                if (newMessagesCount > 0) {
                    var lastSender = null;
                    snapshot.docChanges().forEach(function(change) {
                        if (change.type !== 'added') return;
                        var data = change.doc.data();
                        if (data && data.timestamp) {
                            var ts = data.timestamp.toMillis ? data.timestamp.toMillis() : data.timestamp;
                            if (ts > lastSeenTimestamp) lastSender = data.nome || null;
                        }
                    });
                    unreadCount += newMessagesCount;
                    updateBadge(unreadCount);
                    showNewMsgBar(lastSender);
                    if (maxTs > lastSeenTimestamp) {
                        lastSeenTimestamp = maxTs;
                        localStorage.setItem('yoru_last_msg_ts', lastSeenTimestamp);
                    }
                }
            }, function(error) {
                console.error('Erro no listener Firebase:', error);
            });
    } catch(e) {
        console.error('Falha ao iniciar Firebase:', e);
    }
}

function startFirebaseIntegration() {
    startMessageListener();
    updateBadge(unreadCount);
}

/* ==================== BIND E BOOT ==================== */
function bind(){
  var btnConn=$('btn-connect');
  if(btnConn) btnConn.onclick=function(){
    var raw=app.rawState; if(raw==='PARANDO') return;
    autoSaveCredentials();
    A.connect();
    if(raw==='CONECTADO') applyState('PARANDO','Encerrando túnel...');
    else if(['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO'].indexOf(raw)<0) applyState('INICIANDO','Preparando conexão...');
  };
  var btnLogsQuick = $('btn-logs-quick');
  if(btnLogsQuick) btnLogsQuick.onclick = function(){ renderLogs(); openModal('modal-logs'); };

  var sServ=$('select-server'); if(sServ) sServ.onclick=function(){ if(app.connected){ toast('Desconecte antes de trocar de rede.','err'); return; } buildServerList('normal'); openModal('modal-servers'); };
  var pCard=$('select-premium'); if(pCard) pCard.onclick=function(){ if(app.connected){ toast('Desconecte antes de trocar de rede.','err'); return; } buildServerList('premium'); openModal('modal-servers'); };
  var credsToggle = $('creds-type-toggle'); if (credsToggle) credsToggle.onclick = toggleCredsMode;

  var btnUpdate = $('btn-update-config'); if(btnUpdate) btnUpdate.onclick = function(){ toast('Sincronizando...',''); A.checkUpdate(); };

  var rLog=$('btn-refresh-logs'); if(rLog) rLog.onclick=function(){ renderLogs(); };
  var cLog=$('btn-clear-logs'); if(cLog) cLog.onclick=function(){ A.clearLogs(); var c=$('log-container'); if(c) c.innerHTML='<div style="color:var(--text-muted);padding:8px">Limpo.</div>'; };
  var btnLayouts=$('btn-open-layouts'); if(btnLayouts) btnLayouts.onclick=function(){ openModal('modal-layouts'); };

  var dnsToggle=$('cfg-dns-forward'); if(dnsToggle) { dnsToggle.onchange=function(){ updateDepRows(); autoSaveSettings(); }; }
  var udpToggle=$('cfg-udp-forward'); if(udpToggle) { udpToggle.onchange=function(){ updateDepRows(); autoSaveSettings(); }; }
  var xrayToggle=$('cfg-xray-enabled'); if(xrayToggle) { xrayToggle.onchange=function(){ updateDepRows(); autoSaveSettings(); }; }

  var allSettingSwitches = document.querySelectorAll('#settings-card input[type="checkbox"]');
  allSettingSwitches.forEach(function(sw){ sw.addEventListener('change', autoSaveSettings); });
  var allSettingInputs = document.querySelectorAll('#settings-card input[type="text"], #settings-card input[type="number"], #settings-card select');
  allSettingInputs.forEach(function(inp){ inp.addEventListener('change', autoSaveSettings); inp.addEventListener('blur', autoSaveSettings); });

  var btnAd=$('btn-watch-ad'); if(btnAd) btnAd.onclick=function(){ btnAd.textContent='Aguarde...'; btnAd.disabled=true; A.watchAd(); };
  var termInput = document.getElementById('terminal-input'); if (termInput) termInput.addEventListener('keydown', function(e) { if (e.key === 'Enter') { var cmd = termInput.value; terminalExec(cmd); termInput.value = ''; } });
  document.querySelectorAll('.slide-dot').forEach(function(dot) { dot.onclick = function() { goSlide(parseInt(dot.getAttribute('data-slide'))); }; });

  document.querySelectorAll('.modal-close').forEach(function(b){ b.onclick=closeModal; });
  var mMask=$('modal-mask'); if(mMask) mMask.onclick=function(e){ if(e.target===mMask) closeModal(); };
  setInterval(updateCelestial, 60000);
}

function createBubbles() { for (var i = 0; i < 6; i++) { var bubble = document.createElement('div'); bubble.className = 'floating-bubble'; var size = Math.random() * 80 + 40; bubble.style.width = size + 'px'; bubble.style.height = size + 'px'; bubble.style.left = Math.random() * 100 + 'vw'; bubble.style.top = Math.random() * 100 + 'vh'; bubble.style.animationDuration = (Math.random() * 10 + 8) + 's'; bubble.style.animationDelay = Math.random() * 5 + 's'; document.body.appendChild(bubble); } for (var j = 0; j < 25; j++) { var star = document.createElement('div'); var sSize = Math.random() * 3 + 1; star.className = 'fx-star'; star.style.width = sSize + 'px'; star.style.height = sSize + 'px'; star.style.left = Math.random() * 100 + 'vw'; star.style.top = Math.random() * 100 + 'vh'; star.style.animationDuration = (Math.random() * 3 + 2) + 's'; star.style.animationDelay = Math.random() * 2 + 's'; document.body.appendChild(star); } }

function boot(){
  createBubbles(); updateCelestial(); loadTheme(); loadLayout();
  loadSavedCredentials(); bind(); loadRadical(); initTimeCard();
  refreshInfo(); refreshSelected(); applyState(A.getStatus());
  startPolling(); setInterval(refreshInfo,15000); loadSettings();
  startFirebaseIntegration();
}
if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',boot); else boot();
})();
</script>

